// lib/genai-panels.libsonnet
// Reusable panel constructors for GenAI dashboards.
// Import with: local gp = import "genai-panels.libsonnet";

local g = import "github.com/grafana/grafonnet/gen/grafonnet-latest/main.libsonnet";

{
  // Standard time series panel for GenAI latency metrics
  latencyPanel(title, query, unit="s", legendFormat="{{model}}")::
    g.panel.timeSeries.new(title)
    + g.panel.timeSeries.queryOptions.withTargets([
        g.query.prometheus.new("$datasource", query)
        + g.query.prometheus.withLegendFormat(legendFormat),
      ])
    + g.panel.timeSeries.fieldConfig.defaults.custom.withFillOpacity(8)
    + g.panel.timeSeries.standardOptions.withUnit(unit)
    + g.panel.timeSeries.standardOptions.thresholds.withSteps([
        { color: "green", value: null },
        { color: "yellow", value: 0.8 },
        { color: "red", value: 2.0 },
      ]),

  // Token throughput rate panel
  tokenRatePanel(title, filter="")::
    local q = "sum by (model, token_type) (rate(genai_chat_completion_tokens_total{env="$env"%s}[5m]))" % filter;
    g.panel.timeSeries.new(title)
    + g.panel.timeSeries.queryOptions.withTargets([
        g.query.prometheus.new("$datasource", q)
        + g.query.prometheus.withLegendFormat("{{model}} ({{token_type}})"),
      ])
    + g.panel.timeSeries.standardOptions.withUnit("short")
    + g.panel.timeSeries.panelOptions.withDescription("Token throughput in tokens/second. Separate input and output to identify cost drivers."),

  // Error rate stat panel — red if above SLO
  errorRateStat(title, slo_threshold=0.005)::
    local q = |||
      sum(rate(genai_chat_error_total{env="$env"}[5m]))
        /
      sum(rate(genai_chat_request_total{env="$env"}[5m]))
    |||;
    g.panel.stat.new(title)
    + g.panel.stat.queryOptions.withTargets([
        g.query.prometheus.new("$datasource", q),
      ])
    + g.panel.stat.standardOptions.withUnit("percentunit")
    + g.panel.stat.standardOptions.thresholds.withSteps([
        { color: "green", value: null },
        { color: "yellow", value: slo_threshold * 0.8 },
        { color: "red", value: slo_threshold },
      ]),
}

// dashboards/genai/golden-signals.jsonnet
local g = import "github.com/grafana/grafonnet/gen/grafonnet-latest/main.libsonnet";
local gp = import "../../lib/genai-panels.libsonnet";
local vars = import "../../lib/variables.libsonnet";

g.dashboard.new("GenAI Golden Signals")
+ g.dashboard.withUid("genai-golden-signals-v1")
+ g.dashboard.withDescription("TTFT, error rate, token traffic, and saturation for GenAI services")
+ g.dashboard.withRefresh("30s")
+ g.dashboard.withTimepicker(g.dashboard.timepicker.withRefreshIntervals(["30s","1m","5m"]))
+ g.dashboard.withTemplating({
    list: [
      vars.datasource,
      vars.env,
      vars.model,
      vars.region,
    ]
  })
+ g.dashboard.withPanels([
    // Row 1: Latency
    g.panel.row.new("Latency"),
    gp.latencyPanel(
      title="TTFT p95 (streaming)",
      query=|||
        histogram_quantile(0.95,
          sum by (le, model) (
            rate(genai_chat_ttft_seconds_bucket{env="$env", model=~"$model"}[5m])
          )
        )
      |||,
    ),
    gp.latencyPanel(
      title="End-to-End p95 (non-streaming)",
      query=|||
        histogram_quantile(0.95,
          sum by (le, model) (
            rate(genai_chat_request_duration_seconds_bucket{env="$env", stream="false"}[5m])
          )
        )
      |||,
    ),

    // Row 2: Traffic
    g.panel.row.new("Traffic"),
    gp.tokenRatePanel("Token Throughput by Model"),

    // Row 3: Errors
    g.panel.row.new("Errors"),
    gp.errorRateStat("Error Rate", slo_threshold=0.005),

    // Row 4: Saturation
    g.panel.row.new("Saturation"),
    gp.latencyPanel(
      title="Rate Limit Utilisation",
      query='genai_provider_rate_limit_utilisation_ratio{env="$env"}',
      unit="percentunit",
    ),
  ])

import json
import hashlib
import subprocess
import requests
from pathlib import Path


def dashboard_fingerprint(dashboard_json: dict) -> str:
    """Hash the dashboard content (excluding volatile fields like version and updated time)."""
    clean = {k: v for k, v in dashboard_json.items()
             if k not in ("version", "updatedAt", "id")}
    return hashlib.sha256(
        json.dumps(clean, sort_keys=True).encode()
    ).hexdigest()


def fetch_live_dashboard(uid: str, grafana_url: str, api_key: str) -> dict:
    resp = requests.get(
        f"{grafana_url}/api/dashboards/uid/{uid}",
        headers={"Authorization": f"Bearer {api_key}"},
        timeout=10,
    )
    resp.raise_for_status()
    return resp.json()["dashboard"]


def check_drift(
    rendered_dir: Path,
    grafana_url: str,
    api_key: str,
) -> list[str]:
    drifted = []
    for json_file in rendered_dir.glob("*.json"):
        with open(json_file) as f:
            local_dash = json.load(f)
        uid = local_dash.get("uid")
        if not uid:
            continue
        try:
            live_dash = fetch_live_dashboard(uid, grafana_url, api_key)
        except requests.HTTPError:
            continue   # dashboard may not exist yet

        local_fp = dashboard_fingerprint(local_dash)
        live_fp = dashboard_fingerprint(live_dash)

        if local_fp != live_fp:
            drifted.append(f"{uid} ({json_file.name}): git vs live fingerprint mismatch")

    return drifted


if __name__ == "__main__":
    import os
    drifted = check_drift(
        Path("observability/rendered"),
        os.environ["GRAFANA_URL"],
        os.environ["GRAFANA_API_KEY"],
    )
    if drifted:
        print("DRIFT DETECTED:")
        for d in drifted:
            print(f"  {d}")
        raise SystemExit(1)
    print("No drift detected.")
